namespace EduAssist.API.DTOs;
public class UserDto { public string Id { get; set; } = ""; public string UserName { get; set; } = ""; public string Email { get; set; } = ""; public string FirstName { get; set; } = ""; public string LastName { get; set; } = ""; public string DisplayName { get; set; } = ""; public string Institution { get; set; } = ""; public string Grade { get; set; } = ""; public string Bio { get; set; } = ""; public DateTime? DateOfBirth { get; set; } public DateTime JoinedOn { get; set; } public DateTime LastActiveOn { get; set; } public bool IsActive { get; set; } public string PreferredLanguage { get; set; } = ""; public int TotalQueriesAsked { get; set; } public List<string> Roles { get; set; } = new(); }
public record UserForCreate(string FirstName, string LastName, string DisplayName, string Email, string UserName, string Password, string Institution, string Grade, string Bio, DateTime? DateOfBirth, string PreferredLanguage, string Role);
public record UserForUpdate(string FirstName, string LastName, string DisplayName, string Institution, string Grade, string Bio, DateTime? DateOfBirth, string PreferredLanguage, bool IsActive);
public record UserProfileUpdate(string FirstName, string LastName, string DisplayName, string Institution, string Grade, string Bio, DateTime? DateOfBirth, string PreferredLanguage);
